+:root {
+  color-scheme: light dark;
+  --bg: #07080e;
+  --panel: rgba(12, 14, 22, 0.78);
+  --panel-solid: #0c0e16;
+  --text: rgba(245, 247, 255, 0.93);
+  --muted: rgba(177, 189, 212, 0.78);
+  --line: rgba(255, 255, 255, 0.1);
+  --accent: #7ef3c7;
+  --accent2: #89a7ff;
+  --shadow: rgba(0, 0, 0, 0.42);
+  --radius: 18px;
+  --radius-sm: 14px;
+}
+
+@media (prefers-color-scheme: light) {
+  :root {
+    --bg: #f7fbff;
+    --panel: rgba(255, 255, 255, 0.72);
+    --panel-solid: #ffffff;
+    --text: rgba(11, 16, 22, 0.92);
+    --muted: rgba(55, 69, 88, 0.74);
+    --line: rgba(11, 16, 22, 0.1);
+    --shadow: rgba(11, 16, 22, 0.12);
+  }
+}
+
+* {
+  box-sizing: border-box;
+}
+
+html,
+body {
+  min-height: 100%;
+}
+
+html {
+  background: var(--bg);
+}
+
+body {
+  margin: 0;
+  font: 16px/1.55 ui-sans-serif, "Avenir Next", Avenir, "Segoe UI", "Helvetica Neue", sans-serif;
+  color: var(--text);
+  background:
+    radial-gradient(1100px 800px at 18% 12%, rgba(126, 243, 199, 0.18), transparent 58%),
+    radial-gradient(980px 780px at 86% 18%, rgba(137, 167, 255, 0.18), transparent 60%),
+    radial-gradient(900px 700px at 42% 92%, rgba(126, 243, 199, 0.06), transparent 60%),
+    repeating-linear-gradient(
+      90deg,
+      rgba(255, 255, 255, 0.04),
+      rgba(255, 255, 255, 0.04) 1px,
+      transparent 1px,
+      transparent 72px
+    ),
+    var(--bg);
+}
+
+a,
+a:visited {
+  color: inherit;
+}
+
+a {
+  text-decoration: none;
+}
+
+a:hover {
+  text-decoration: underline;
+}
+
+code {
+  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", monospace;
+  font-size: 0.95em;
+}
+
+.wrap {
+  max-width: 1040px;
+  margin: 0 auto;
+  padding: 46px 22px 34px;
+}
+
+.top {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  gap: 18px;
+  margin-bottom: 28px;
+}
+
+.brand {
+  display: flex;
+  align-items: center;
+  gap: 14px;
+  min-width: 240px;
+}
+
+.name {
+  display: flex;
+  flex-direction: column;
+  gap: 2px;
+}
+
+.title {
+  margin: 0;
+  font-family: ui-serif, "New York", "Iowan Old Style", Palatino, serif;
+  font-size: 22px;
+  letter-spacing: 0.1px;
+}
+
+.tagline {
+  margin: 0;
+  color: var(--muted);
+  font-size: 13.5px;
+}
+
+.mark {
+  width: 44px;
+  height: 44px;
+  border-radius: 13px;
+  border: 0;
+  box-shadow: none;
+  background: transparent;
+  object-fit: cover;
+  filter: drop-shadow(0 12px 24px rgba(0, 0, 0, 0.35));
+}
+
+.brand:hover .mark {
+  filter: drop-shadow(0 16px 34px rgba(0, 0, 0, 0.42));
+}
+
+.links {
+  display: flex;
+  gap: 10px;
+}
+
+.btn {
+  padding: 10px 12px;
+  border-radius: 13px;
+  border: 1px solid var(--line);
+  background: color-mix(in srgb, var(--panel-solid) 18%, transparent);
+  box-shadow: 0 10px 30px var(--shadow);
+  transition: transform 160ms ease, background 160ms ease, border-color 160ms ease;
+  white-space: nowrap;
+}
+
+.btn:hover {
+  transform: translateY(-1px);
+  text-decoration: none;
+  border-color: color-mix(in srgb, var(--accent) 32%, var(--line));
+}
+
+.btn.primary {
+  border-color: transparent;
+  background: linear-gradient(135deg, rgba(126, 243, 199, 0.6), rgba(137, 167, 255, 0.58));
+}
+
+.btn.ghost {
+  background: transparent;
+}
+
+.hero {
+  display: grid;
+  grid-template-columns: 1.05fr 0.95fr;
+  gap: 26px;
+  align-items: center;
+  padding: 22px;
+  border: 1px solid var(--line);
+  border-radius: var(--radius);
+  background: var(--panel);
+  backdrop-filter: blur(12px);
+  box-shadow: 0 18px 60px var(--shadow);
+  position: relative;
+  overflow: hidden;
+}
+
+.copy {
+  position: relative;
+  z-index: 1;
+}
+
+.hero::before {
+  content: "";
+  position: absolute;
+  inset: -1px;
+  background:
+    radial-gradient(560px 320px at 10% 15%, rgba(126, 243, 199, 0.18), transparent 55%),
+    radial-gradient(520px 300px at 92% 18%, rgba(137, 167, 255, 0.18), transparent 55%);
+  pointer-events: none;
+  opacity: 0.9;
+}
+
+.copy h2 {
+  margin: 0 0 8px;
+  font-family: ui-serif, "New York", "Iowan Old Style", Palatino, serif;
+  font-size: 34px;
+  letter-spacing: -0.3px;
+  line-height: 1.12;
+  position: relative;
+}
+
+.copy p {
+  margin: 0 0 10px;
+  color: var(--muted);
+}
+
+.badges {
+  display: flex;
+  flex-wrap: wrap;
+  gap: 8px;
+  margin-bottom: 10px;
+  position: relative;
+}
+
+.badge {
+  font-size: 12px;
+  padding: 6px 10px;
+  border-radius: 999px;
+  border: 1px solid var(--line);
+  background: color-mix(in srgb, var(--panel-solid) 14%, transparent);
+  color: color-mix(in srgb, var(--text) 86%, var(--muted));
+  letter-spacing: 0.2px;
+}
+
+.cta {
+  display: flex;
+  gap: 10px;
+  flex-wrap: wrap;
+  margin-top: 14px;
+  position: relative;
+}
+
+.bullets {
+  margin: 14px 0 0;
+  padding: 0 0 0 18px;
+  color: var(--muted);
+  font-size: 13.5px;
+  position: relative;
+}
+
+.bullets li {
+  margin: 6px 0;
+}
+
+.shot {
+  margin: 0;
+  position: relative;
+  z-index: 1;
+}
+
+.shot img {
+  width: 100%;
+  height: auto;
+  border-radius: var(--radius-sm);
+  border: 1px solid var(--line);
+  box-shadow: 0 18px 60px var(--shadow);
+  background: color-mix(in srgb, var(--panel-solid) 92%, transparent);
+  transform: perspective(900px) rotateY(-6deg) rotateX(2deg);
+  transition: transform 220ms ease, box-shadow 220ms ease;
+}
+
+.shot img:hover {
+  transform: perspective(900px) rotateY(-2deg) rotateX(0deg) translateY(-2px);
+  box-shadow: 0 24px 80px var(--shadow);
+}
+
+.details {
+  display: grid;
+  grid-template-columns: repeat(3, 1fr);
+  gap: 14px;
+  margin-top: 14px;
+}
+
+.card {
+  border: 1px solid var(--line);
+  border-radius: var(--radius);
+  padding: 14px 14px 12px;
+  background: var(--panel);
+  backdrop-filter: blur(10px);
+  box-shadow: 0 14px 40px var(--shadow);
+}
+
+.card h3 {
+  margin: 0 0 6px;
+  font-size: 13px;
+  letter-spacing: 0.2px;
+  text-transform: uppercase;
+  color: color-mix(in srgb, var(--text) 88%, var(--muted));
+}
+
+.card p {
+  margin: 0;
+  color: var(--muted);
+  font-size: 13.5px;
+}
+
+.wide {
+  margin-top: 14px;
+}
+
+.wide-shot img {
+  transform: none;
+}
+
+.wide-shot img:hover {
+  transform: translateY(-2px);
+}
+
+.foot {
+  margin-top: 22px;
+  text-align: center;
+  color: var(--muted);
+  font-size: 13px;
+}
+
+.foot a {
+  text-decoration: underline;
+  text-decoration-color: color-mix(in srgb, var(--muted) 45%, transparent);
+}
+
+[data-animate] {
+  opacity: 0;
+  transform: translateY(10px);
+  animation: rise 680ms cubic-bezier(0.2, 0.9, 0.2, 1) forwards;
+  animation-delay: calc(var(--d, 0) * 90ms);
+}
+
+[data-animate="1"] {
+  --d: 1;
+}
+
+[data-animate="2"] {
+  --d: 2;
+}
+
+[data-animate="3"] {
+  --d: 3;
+}
+
+[data-animate="4"] {
+  --d: 4;
+}
+
+[data-animate="5"] {
+  --d: 5;
+}
+
+[data-animate="6"] {
+  --d: 6;
+}
+
+@keyframes rise {
+  to {
+    opacity: 1;
+    transform: translateY(0);
+  }
+}
+
+@media (prefers-reduced-motion: reduce) {
+  [data-animate] {
+    animation: none;
+    opacity: 1;
+    transform: none;
+  }
+  .btn,
+  .shot img {
+    transition: none;
+  }
+}
+
+@media (max-width: 860px) {
+  .top {
+    flex-direction: column;
+    align-items: flex-start;
+  }
+  .hero {
+    grid-template-columns: 1fr;
+  }
+  .details {
+    grid-template-columns: 1fr;
+  }
+  .shot img {
+    transform: none;
+  }
+}
